-      }, 3000);
-    }
-  }, [isCopy]);
-
-  const IconSize = 16;
+  const iconSize = 16;
 
   return (
     <CopyToClipboard
-      onCopy={handleCopyClick}
+      onCopy={onCopyClick}
       title={`${tooltipTitle} (${isCopy ? 'Copied!' : 'Copy'})`}
