If so, we need to put the `seleted_nodes` into the context, because the single scheduling will rely on the `seleted_nodes` when doing batch scheduling. Like this:

```
struct SchedulingContext {
  virtual ~SchedulingContext() = default;
  // The nodes successfully scheduled.
  std::vector<scheduling::NodeID> selected_nodes_;
};

class ISingleSchedulePolicy : public ISchedulingPolicy {
 public:
  virtual ~ISingleSchedulePolicy() = default;

  SchedulingResult BatchSchedule(
      const std::vector<const ResourceRequest *> &resource_request_list,
      const SchedulingOptions &options,
      SchedulingContext *context = nullptr) override {
    for (auto &resource_request : resource_request_list) {
      auto result = Schedule(*resource_request, options, context);
      if (!result.status.IsSuccess()) {
        return result;
      }
      RAY_CHECK(result.selected_nodes.size() == 0);
      context->selected_nodes_.emplace_back(result.selected_nodes[0]);
    }

    return SchedulingResult::Success(std::move(context->selected_nodes_));
  }
};

class IBatchSchedulePolicy : public ISchedulingPolicy {
 public:
  virtual ~IBatchSchedulePolicy() = default;

  SchedulingResult Schedule(const ResourceRequest &resource_request,
                            const SchedulingOptions &options,
                            SchedulingContext *context = nullptr) override {
    return BatchSchedule({&resource_request}, options, context);
  }
};
```

